103→/// Collected struct definitions from the same file.
104→type StructDefs = HashMap<String, Vec<(String, syn::Type)>>;
105→
106→/// Collected enum definitions: maps enum name → Vec of (variant_name, fields).
107→type EnumDefs = HashMap<String, Vec<(String, syn::Fields)>>;
108→
109→fn collect_struct_defs(file: &syn::File) -> StructDefs {
110→    let mut defs = HashMap::new();
111→    for item in &file.items {
112→        if let syn::Item::Struct(s) = item
113→            && let syn::Fields::Named(fields) = &s.fields
114→        {
115→            let field_list: Vec<(String, syn::Type)> = fields
116→                .named
117→                .iter()
118→                .filter_map(|f| {
119→                    f.ident.as_ref().map(|id| (id.to_string(), f.ty.clone()))
120→                })
121→                .collect();
122→            defs.insert(s.ident.to_string(), field_list);
123→        }
124→    }
125→    defs
126→}
127→
128→fn collect_enum_defs(file: &syn::File) -> EnumDefs {
129→    let mut defs = HashMap::new();
130→    for item in &file.items {
131→        if let syn::Item::Enum(e) = item {
132→            let variants: Vec<(String, syn::Fields)> = e
133→                .variants
134→                .iter()
135→                .map(|v| (v.ident.to_string(), v.fields.clone()))
136→                .collect();
137→            defs.insert(e.ident.to_string(), variants);
138→        }
139→    }
140→    defs
141→}
