 70→/// Instrument Rust source code from a string.
 71→pub fn instrument_source(
 72→    source: &str,
 73→    function_name: Option<&str>,
 74→) -> Result<InstrumentResult, InstrumentError> {
 75→    let mut syntax = parse_file(source)
 76→        .map_err(|e| InstrumentError::ParseError(e.to_string()))?;
 77→
 78→    let mut visitor = Instrumentor::new(function_name);
 79→    visitor.visit_file_mut(&mut syntax);
 80→
 81→    let output = syntax.to_token_stream().to_string();
 82→
 83→    Ok(InstrumentResult {
 84→        source: output,
 85→        branch_count: visitor.branch_id,
 86→    })
 87→}
